# skeptic/B1: packet-only for S09-T2-B-E3
def good_title(s: str) -> str:
    parts = []
    for i, w in enumerate(s.split()):
        if i > 0 and w.lower() in {'de', 'del', 'la'}:
            parts.append(w.lower())
        else:
            parts.append(w[:1].upper() + w[1:].lower() if w else w)
    return ' '.join(parts)

def test(fn):
    out = fn('juan de la cruz')
    assert out == 'Juan de la Cruz', out
    return 'pass'

print('GREEN', test(good_title))

