# skeptic/B1: packet-only for S09-T4-B-E2
def retry_call(fn, max_attempts=3):
    last = None
    for attempt in range(1, max_attempts + 1):
        try:
            return fn()
        except TimeoutError as e:
            last = e
    raise last

n = {"c": 0}

def flaky():
    n["c"] += 1
    if n["c"] < 3:
        raise TimeoutError("x")
    return "done"

print(retry_call(flaky), "calls", n["c"])

